195→        'react-native-svg',
196→        'react-native-svg-charts',
197→        '@semparar/design-system-app',
198→      ],
199→    },
200→  },
201→
202→  addons: ['@storybook/addon-essentials'],
203→
204→  viteFinal: async config => {
205→    config.plugins = config.plugins || [];
206→    config.plugins.push(dtsStubPlugin());
207→    config.plugins.push(circularFixPlugin());
208→    config.plugins.push(jsxInJsPlugin());
209→    config.plugins.push(cjsToEsmPlugin());
210→
211→    config.optimizeDeps = config.optimizeDeps || {};
212→    config.optimizeDeps.include = [
213→      ...(config.optimizeDeps.include || []),
214→      'styled-components',
215→      'styled-components/native',
216→      'card-validator',
217→      'credit-card-type',
218→      'lodash',
219→      'xdate',
220→      'invariant',
221→      'fbjs',
222→      'hoist-non-react-statics',
223→      'prop-types',
224→      'object-assign',
225→      'shallowequal',
226→      'moment',
227→    ];
228→
229→    config.resolve = config.resolve || {};
230→    config.resolve.alias = {
231→      ...(config.resolve.alias || {}),
232→      '~': path.resolve(__dirname, '../src'),
233→      '~/store': path.resolve(__dirname, 'mocks/store.ts'),
234→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
235→      'react-native-linear-gradient': path.resolve(
236→        __dirname,
237→        'mocks/react-native-linear-gradient.tsx',
238→      ),
239→      'react-native-modalize': path.resolve(
240→        __dirname,
241→        'mocks/react-native-modalize.tsx',
242→      ),
243→      'react-native-skeleton-placeholder': path.resolve(
244→        __dirname,
245→        'mocks/react-native-skeleton-placeholder.tsx',
246→      ),
247→      '@react-native-community/slider': path.resolve(
248→        __dirname,
249→        'mocks/react-native-community-slider.tsx',
250→      ),
251→      'lottie-react-native': path.resolve(
252→        __dirname,
253→        'mocks/lottie-react-native.tsx',
254→      ),
255→      'react-native-video': path.resolve(
256→        __dirname,
257→        'mocks/react-native-video.tsx',
258→      ),
259→      '@react-native/assets-registry/registry': path.resolve(
260→        __dirname,
261→        'mocks/react-native-assets-registry.tsx',
262→      ),
263→      'deprecated-react-native-prop-types': path.resolve(
264→        __dirname,
265→        'mocks/deprecated-react-native-prop-types.tsx',
